// ============================================================
// FILTER: Only process rows due for posting
// Checks BestTimeSlot against current hour
// ============================================================
const now = new Date();
const currentHour = now.getHours();
const currentDay  = now.toISOString().split('T')[0]; // YYYY-MM-DD

const results = [];

for (const item of $input.all()) {
  const row = item.json;

  // Skip if already posted
  if (row.Status === 'Posted' || row.Status === 'Failed') continue;
  if (row.Status !== 'Ready') continue;

  // Parse scheduled time slot (format: 'HH' or 'YYYY-MM-DD HH')
  const slot = (row.BestTimeSlot || '').toString().trim();
  const scheduledHour = slot.includes(' ') ? parseInt(slot.split(' ')[1]) : parseInt(slot);
  const scheduledDate = slot.includes(' ') ? slot.split(' ')[0] : currentDay;

  // Check if it's time to post
  const isDue = (!slot) || // no time = post immediately
                (scheduledDate === currentDay && scheduledHour === currentHour);

  if (!isDue) continue;

  // Parse platforms list
  const platforms = (row.Platforms || 'linkedin,instagram,twitter')
    .split(',').map(p => p.trim().toLowerCase()).filter(Boolean);

  results.push({ json: {
    row_id:       row.ID || row.RowNumber || '',
    topic:        row.Topic || '',
    raw_content:  row.RawContent || row.Content || '',
    media_url:    row.MediaURL || '',
    platforms,
    tone:         row.Tone || 'professional',
    hashtags:     row.Hashtags || '',
    brand_voice:  row.BrandVoice || 'We are a tech startup focused on AI automation.',
    scheduled_at: slot,
    sheet_row:    row._rowNumber || 0
  }});
}

console.log(`Due for posting: ${results.length} items`);
return results.length > 0 ? results : [{ json: { skip: true, message: 'No items due' } }];

