// ============================================================
// PARSE & FORMAT AI CONTENT
// Parse OpenAI JSON response and format per platform
// ============================================================
const results = [];

for (const item of $input.all()) {
  const meta = item.json;

  // Parse AI response
  let aiContent;
  try {
    const rawText = meta.message?.content || meta.content || meta.choices?.[0]?.message?.content || '';
    const cleaned = rawText.replace(/```json\n?/gi, '').replace(/```/gi, '').trim();
    aiContent = JSON.parse(cleaned);
  } catch (e) {
    console.log('JSON parse error:', e.message);
    aiContent = {
      linkedin:  { caption: meta.raw_content, hashtags: [] },
      instagram: { caption: meta.raw_content, hashtags: [] },
      twitter:   { tweet: meta.raw_content.slice(0, 250) },
      facebook:  { post: meta.raw_content },
      youtube:   { title: meta.topic, description: meta.raw_content },
      tiktok:    { caption: meta.raw_content.slice(0, 100) }
    };
  }

  const platforms = meta.platforms || ['linkedin'];
  const mediaUrl  = meta.media_url || '';
  const topic     = meta.topic || '';
  const rowId     = meta.row_id || '';
  const sheetRow  = meta.sheet_row || 0;

  // Best posting times (24h format, per platform)
  const bestTimes = {
    linkedin:  [8, 10, 12, 17],  // weekday mornings
    instagram: [7, 11, 14, 19],  // morning + evening
    twitter:   [8, 12, 17, 21],  // spread throughout day
    facebook:  [9, 13, 15, 19],
    youtube:   [14, 16, 18],
    tiktok:    [7, 12, 19, 22]
  };

  // Generate per-platform post objects
  for (const platform of platforms) {
    if (!aiContent[platform]) continue;

    const p = aiContent[platform];
    let caption = '';
    let hashtags = [];

    switch (platform) {
      case 'linkedin':
        caption   = p.caption || '';
        hashtags  = p.hashtags || [];
        break;
      case 'instagram':
        caption   = p.caption || '';
        hashtags  = p.hashtags || [];
        break;
      case 'twitter':
        caption   = p.tweet || '';
        hashtags  = [];
        break;
      case 'facebook':
        caption   = p.post || '';
        hashtags  = p.hashtags || [];
        break;
      case 'youtube':
        caption   = p.description || '';
        hashtags  = p.tags || [];
        break;
      case 'tiktok':
        caption   = p.caption || '';
        hashtags  = p.hashtags || [];
        break;
    }

    // Build full text with hashtags
    const hashtagStr = hashtags.map(h => h.startsWith('#') ? h : `#${h}`).join(' ');
    const fullCaption = platform === 'twitter'
      ? caption  // Twitter: already includes hashtags
      : `${caption}\n\n${hashtagStr}`.trim();

    results.push({ json: {
      platform,
      row_id:        rowId,
      sheet_row:     sheetRow,
      topic,
      caption:       fullCaption,
      media_url:     mediaUrl,
      hashtags,
      ai_full:       aiContent,
      youtube_title: aiContent.youtube?.title || topic,
      youtube_tags:  aiContent.youtube?.tags  || [],
      tiktok_hook:   aiContent.tiktok?.hook   || '',
      twitter_thread:aiContent.twitter?.thread || [],
      linkedin_hook: aiContent.linkedin?.hook  || '',
      ig_story:      aiContent.instagram?.story_text || '',
      best_times:    bestTimes[platform] || [9],
      created_at:    new Date().toISOString()
    }});
  }
}

console.log(`Formatted ${results.length} platform posts`);
return results;

// ============================================================
// RESPONSE COLLECTOR
// Normalizes API responses from all platforms
// Extracts post URLs, IDs, and status codes
// ============================================================
const results = [];

for (const item of $input.all()) {
  const j = item.json;
  const httpCode = j.statusCode || j.status || 200;
  const success  = httpCode >= 200 && httpCode < 300 || j.id;

  // Extract post URL/ID per platform
  let postId  = null;
  let postUrl = null;

  if (j.id) {
    // LinkedIn returns id as 'urn:li:share:...'
    // Instagram returns numeric id
    // Twitter returns data.id
    // Facebook returns id
    postId  = j.id || j.data?.id || '';
    const platform = $input.first()?.json?.platform || 'unknown';
    switch (platform) {
      case 'linkedin':  postUrl = `https://www.linkedin.com/feed/update/${postId}`; break;
      case 'instagram': postUrl = `https://www.instagram.com/p/${postId}`; break;
      case 'twitter':   postUrl = `https://twitter.com/i/web/status/${postId}`; break;
      case 'facebook':  postUrl = `https://www.facebook.com/${postId}`; break;
      case 'youtube':   postUrl = `https://youtube.com/watch?v=${postId}`; break;
      case 'tiktok':    postUrl = `https://www.tiktok.com/@user/video/${postId}`; break;
    }
  }

  results.push({ json: {
    platform:  j.platform  || 'unknown',
    row_id:    j.row_id    || '',
    sheet_row: j.sheet_row || 0,
    topic:     j.topic     || '',
    post_id:   postId,
    post_url:  postUrl,
    status:    success ? 'posted' : 'failed',
    http_code: httpCode,
    error:     success ? null : (j.message || j.error?.message || 'API error'),
    posted_at: new Date().toISOString()
  }});
}

return results;

